// Prepare data for database update and response
const inputData = $input.first().json;

// DEBUG - See what's coming in
console.log('=== PREPARE UPDATE DATA DEBUG ===');
console.log('Input phone_number:', inputData.phone_number);
console.log('Input response_text:', inputData.response_text);

// 1. Phone number - ALREADY HAS code 55 from Validate Input Data
let phone_with_code = String(inputData.phone_number || '');
phone_with_code = phone_with_code.replace(/[^0-9]/g, '');

// Create version without code for compatibility
let phone_without_code = phone_with_code;
if (phone_with_code.startsWith('55')) {
    phone_without_code = phone_with_code.substring(2);
}

console.log('Phone with code:', phone_with_code);
console.log('Phone without code:', phone_without_code);

// 2. Response and State Machine state
const response_text = inputData.response_text || 'Olá! Como posso ajudar?';
const next_stage = inputData.next_stage || inputData.current_state || 'greeting';
const collected_data = inputData.collected_data || {};

// 3. Prepare JSON for database (PostgreSQL JSONB)
const collected_data_json = JSON.stringify(collected_data);

// 4. RETURN structured data for next nodes
return {
  // Phone formats for SQL queries - CRITICAL!
  phone_with_code: phone_with_code,      // "556181755748"
  phone_without_code: phone_without_code, // "6181755748"

  // For Send WhatsApp Response
  phone_number: phone_with_code,
  response_text: response_text,

  // For Update Conversation State
  next_stage: next_stage,
  collected_data: collected_data,
  collected_data_json: collected_data_json,

  // Metadata
  timestamp: new Date().toISOString(),

  // Ensure output
  alwaysOutputData: true
};

// Build SQL Queries Node - Prepara todas as queries SQL
// Recebe dados do node anterior
const data = $input.first().json;
const phone_with_code = data.phone_with_code || '';
const phone_without_code = data.phone_without_code || '';

// Validação de segurança
if (!phone_with_code || !phone_without_code) {
  throw new Error('Phone numbers not properly formatted');
}

// Escape simples para SQL injection
const escapeSql = (str) => {
  return String(str).replace(/'/g, "''");
};

// Query para contar conversas existentes
const query_count = `
  SELECT COUNT(*) as count
  FROM conversations
  WHERE phone_number IN ('${escapeSql(phone_with_code)}', '${escapeSql(phone_without_code)}')
`.trim();

// Query para buscar detalhes da conversa
const query_details = `
  SELECT
    *,
    COALESCE(state_machine_state,
      CASE current_state
        WHEN 'novo' THEN 'greeting'
        WHEN 'identificando_servico' THEN 'service_selection'
        WHEN 'coletando_dados' THEN 'collect_name'
        WHEN 'agendando' THEN 'scheduling'
        WHEN 'handoff_comercial' THEN 'handoff_comercial'
        WHEN 'concluido' THEN 'completed'
        ELSE 'greeting'
      END
    ) as state_for_machine
  FROM conversations
  WHERE phone_number IN ('${escapeSql(phone_with_code)}', '${escapeSql(phone_without_code)}')
  ORDER BY updated_at DESC
  LIMIT 1
`.trim();

// Query para criar/atualizar conversa
const query_upsert = `
  -- Limpar duplicatas antigas
  DELETE FROM conversations
  WHERE phone_number IN ('${escapeSql(phone_with_code)}', '${escapeSql(phone_without_code)}')
  AND id NOT IN (
    SELECT id FROM conversations
    WHERE phone_number IN ('${escapeSql(phone_with_code)}', '${escapeSql(phone_without_code)}')
    ORDER BY updated_at DESC
    LIMIT 1
  );

  -- Inserir ou atualizar conversa
  INSERT INTO conversations (
    phone_number,
    whatsapp_name,
    service_id,
    contact_name,
    contact_email,
    city,
    current_state,
    state_machine_state,
    collected_data,
    error_count,
    created_at,
    updated_at
  ) VALUES (
    '${escapeSql(phone_without_code)}',
    '${escapeSql(data.whatsapp_name || '')}',
    NULL,
    NULL,
    NULL,
    NULL,
    'novo',
    'greeting',
    '{}'::jsonb,
    0,
    CURRENT_TIMESTAMP,
    CURRENT_TIMESTAMP
  )
  ON CONFLICT (phone_number) DO UPDATE SET
    whatsapp_name = COALESCE(EXCLUDED.whatsapp_name, conversations.whatsapp_name),
    last_message_at = CURRENT_TIMESTAMP,
    updated_at = CURRENT_TIMESTAMP,
    state_machine_state = CASE
      WHEN conversations.state_machine_state IN ('completed', 'handoff_comercial')
      THEN 'greeting'
      ELSE conversations.state_machine_state
    END
  RETURNING *
`.trim();

// Log para debug
console.log('=== BUILD SQL QUERIES (FIXED) ===');
console.log('Phone with code:', phone_with_code);
console.log('Phone without code:', phone_without_code);
console.log('Queries built successfully as STRINGS');

// IMPORTANTE: Retornar cada query como campo string individual
return {
  ...data,
  query_count: query_count,        // String SQL
  query_details: query_details,    // String SQL
  query_upsert: query_upsert       // String SQL
};

// Merge Queries Node - Preserva todos os campos de query
// Este node garante que os campos query_* sejam preservados após o IF node

const inputData = $input.first().json;
const queryData = $node["Build SQL Queries"].json;

// Log para debug
console.log('=== MERGE QUERIES DEBUG ===');
console.log('Input has count:', inputData.count);
console.log('Query data available:', !!queryData);

// Merge todos os dados preservando os campos de query
return {
    ...inputData,
    // Preservar todos os campos de query do Build SQL Queries
    query_count: queryData.query_count,
    query_details: queryData.query_details,
    query_upsert: queryData.query_upsert,
    queries: queryData.queries,
    // Preservar dados do telefone
    phone_with_code: queryData.phone_with_code,
    phone_without_code: queryData.phone_without_code,
    phone_number: queryData.phone_number,
    // Manter o count do resultado anterior
    count: inputData.count || 0,
    // Pass through outros dados
    whatsapp_name: queryData.whatsapp_name || inputData.whatsapp_name || ''
};
